void heapifyUp(int* arr, int n, int key) { 
  arr[0] = key; 
  for (int i = 0; i <= n; i++) { 
    int parent = (i - 1) / 2; 
    if (parent < 0) break; 
    if (arr[parent] > arr[i]) { 
      // swap(arr[parent], arr[i]); 
      int temp = arr[parent]; 
      arr[parent] = arr[i]; 
      arr[i] = temp; 
    } 
  } 
}

